const trades = $input.all().map(i => i.json);

if (trades.length === 0) {
  return [{ json: { response: 'No trades found in the last 30 days.' } }];
}

const total = trades.length;
const wins = trades.filter(t => t.outcome === 'WIN').length;
const losses = trades.filter(t => t.outcome === 'LOSS').length;
const winRate = total > 0 ? Math.round((wins / total) * 100) : 0;
const totalPnl = Math.round(trades.reduce((sum, t) => sum + (parseFloat(t.pnl_amount) || 0), 0) * 100) / 100;

let response = `TRADE HISTORY (last 30 days)\n`;
response += `Total: ${total} trades | Wins: ${wins} | Losses: ${losses} | Win rate: ${winRate}%\n`;
response += `Total P&L: $${totalPnl >= 0 ? '+' : ''}${totalPnl}\n\n`;

for (const t of trades) {
  const pnlSign = parseFloat(t.pnl_amount) >= 0 ? '+' : '';
  response += `${t.session_date} | ${t.ticker} | Buy: $${t.buy_price} | Sell: $${t.sell_price} | Qty: ${t.quantity} | P&L: ${pnlSign}$${t.pnl_amount} (${pnlSign}${t.pnl_pct}%) | ${t.outcome}`;
  if (t.feedback_tags) { try { const tags = JSON.parse(t.feedback_tags); if (Array.isArray(tags) && tags.length > 0) response += ` | Tags: ${tags.join(', ')}`; } catch(e) {} }
  response += '\n';
}

return [{ json: { response } }];
